// Parse and prepare working state from request body
const body = $input.first().json.body;

const day = body.day ?? 1;
const closeItEnabled = body.closeItEnabled !== false;
const leads = body.leads ?? [];
const threads = body.threads ?? {};

// Stringify existing lead names+emails for dedup check
const existingNames = leads.map(l => l.name.toLowerCase());
const existingEmails = leads.map(l => l.email.toLowerCase());

// Leads eligible for reply today (not closed/nurture, has been contacted, has thread)
const ACTIVE_STATUSES = ['Contacted', 'Awaiting Reply', 'Replied', 'Discovery Booked'];
const activeLeads = leads.filter(l => ACTIVE_STATUSES.includes(l.status));

// Random selection for replies: probability based on intentSignal
const replyingLeads = activeLeads.filter(lead => {
  if (lead.status === 'Discovery Booked') return false; // discovery already booked, no generic replies
  const thread = threads[lead.id] ?? [];
  const lastMsg = thread[thread.length - 1];
  if (!lastMsg) return false;
  // Lead doesn't reply to themselves
  if (lastMsg.from === 'lead') return false;
  // Check if enough days have passed since last reply
  const daysSinceContact = day - (lead.lastReplyDay ?? lead.registeredOnDay);
  if (daysSinceContact < lead.replyFrequencyDays) return false;
  // Probability by intent
  const prob = lead.intentSignal === 'high' ? 0.85 : lead.intentSignal === 'medium' ? 0.55 : 0.25;
  return Math.random() < prob;
});

// CloseIt follow-up candidates: leads that are Contacted/Awaiting Reply, no discovery booked yet
// CloseIt sends 1 follow-up every 2 days, max 4 times
const followUpCandidates = closeItEnabled ? leads.filter(lead => {
  if (!['Contacted', 'Awaiting Reply'].includes(lead.status)) return false;
  if ((lead.agentFollowUpCount ?? 0) >= 4) return false; // maxed out
  const lastFollowUp = lead.lastAgentFollowUpDay ?? lead.registeredOnDay;
  return (day - lastFollowUp) >= 2;
}) : [];

// Post-MoM nudge: discovery booked + MoM completed + last thread msg is from lead (user hasn't replied)
const momNudgeLeads = leads.filter(lead => {
  if (lead.status !== 'Discovery Booked') return false;
  const thread = threads[lead.id] ?? [];
  const lastMsg = thread[thread.length - 1];
  return lastMsg && lastMsg.from === 'lead';
});

return [{
  json: {
    day, closeItEnabled, leads, threads, existingNames, existingEmails,
    activeLeads, replyingLeads, followUpCandidates, momNudgeLeads
  }
}];

