const state = $('Parse State').first().json;
const day = state.day;
const existingNames = state.existingNames ?? [];
const existingEmails = state.existingEmails ?? [];

// Parse OpenAI response
const raw = $input.first().json.choices?.[0]?.message?.content ?? '[]';
let generated = [];
try {
  const cleaned = raw.replace(/```json|```/g, '').trim();
  generated = JSON.parse(cleaned);
} catch { generated = []; }

// Dedup and assign IDs
const newLeads = generated
  .filter(l => l.name && !existingNames.includes(l.name.toLowerCase()) && !existingEmails.includes((l.email ?? '').toLowerCase()))
  .map((l, i) => ({
    id: `n8n_lead_d${day}_${i}`,
    name: l.name,
    company: l.company ?? 'Unknown Co',
    industry: l.industry ?? 'General',
    email: l.email ?? `${l.name.toLowerCase().replace(/\s+/g,'.')}@${(l.company ?? 'co').toLowerCase().replace(/[^a-z]/g,'')}.com`,
    startType: l.startType ?? 'cold',
    intentSignal: l.intentSignal ?? 'medium',
    replyFrequencyDays: Number(l.replyFrequencyDays) || 3,
    inboundMessage: l.inboundMessage ?? null,
    score: 6,
    scoreDelta: 0,
    status: 'New',
    registeredOnDay: day,
    lastReplyDay: null,
    lastUserReplyDay: null,
    discoveryCallDay: null,
    agentFollowUpCount: 0,
    lastAgentFollowUpDay: null
  }));

return [{ json: { newLeads, day } }];

