const state = $('Parse State').first().json;
const { day, leads, threads, replyingLeads, followUpCandidates, momNudgeLeads, newLeads: _ } = state;

// Parse lead replies
const replyRaw = $('OpenAI: Generate Lead Replies').first().json.choices?.[0]?.message?.content ?? '[]';
let replies = [];
try { replies = JSON.parse(replyRaw.replace(/```json|```/g,'').trim()); } catch {}

// Parse follow-up emails
const fuRaw = $('OpenAI: Generate Follow-ups').first()?.json?.choices?.[0]?.message?.content ?? '[]';
let followUpEmails = [];
try { followUpEmails = JSON.parse(fuRaw.replace(/```json|```/g,'').trim()); } catch {}

const newLeads = $('Process New Leads').first().json.newLeads ?? [];

// ── Build outputs ────────────────────────────────────────────────────────────
const threadMessages = [];
const statusUpdates = [];
const agentActions = [];
const notifications = [];
const tasks = [];
const leadUpdates = [];

// 1. New lead arrivals
for (const l of newLeads) {
  notifications.push({ type: 'lead_arrived', message: `New lead: ${l.name} from ${l.company} (${l.startType === 'warm' ? 'warm inbound' : 'cold outreach'})` });
  if (l.startType === 'warm' && l.inboundMessage) {
    threadMessages.push({ leadId: l.id, from: 'lead', body: l.inboundMessage, day });
    statusUpdates.push({ leadId: l.id, status: 'Replied' });
  }
}

// 2. Lead replies
for (const r of replies) {
  const lead = replyingLeads.find(l => l.id === r.leadId);
  if (!lead || !r.replyText) continue;
  threadMessages.push({ leadId: r.leadId, from: 'lead', body: r.replyText, day });
  if (r.containsBookingSignal && lead.status !== 'Discovery Booked') {
    const callDay = day + 1;
    statusUpdates.push({ leadId: r.leadId, status: 'Discovery Booked', discoveryCallDay: callDay });
    agentActions.push({ id: `act_${day}_disc_${r.leadId}`, day, type: 'discovery_call_booked', leadId: r.leadId, leadName: lead.name, summary: `Discovery call booked with ${lead.name} (${lead.company}) — Day ${callDay}`, actor: 'ai', detail: { callDay }, timestamp: new Date().toISOString() });
    tasks.push({ leadId: r.leadId, leadName: lead.name, company: lead.company, callDay });
    notifications.push({ type: 'call_booked', message: `Discovery call booked with ${lead.name} (${lead.company})` });
  } else {
    statusUpdates.push({ leadId: r.leadId, status: 'Replied' });
  }
  agentActions.push({ id: `act_${day}_reply_${r.leadId}`, day, type: 'lead_replied', leadId: r.leadId, leadName: lead.name, summary: `${lead.name} replied`, actor: 'lead', detail: { body: r.replyText }, timestamp: new Date().toISOString() });
}

// 3. CloseIt follow-up emails
for (const fu of followUpEmails) {
  const lead = followUpCandidates.find(l => l.id === fu.leadId);
  if (!lead || !fu.emailBody) continue;
  threadMessages.push({ leadId: fu.leadId, from: 'agent', body: fu.emailBody, day });
  agentActions.push({ id: `act_${day}_fu_${fu.leadId}`, day, type: 'initial_email_sent', leadId: fu.leadId, leadName: lead.name, summary: `Follow-up #${(lead.agentFollowUpCount ?? 0)+1} sent to ${lead.name} — booking discovery call`, actor: 'ai', detail: { body: fu.emailBody, followUpNum: (lead.agentFollowUpCount ?? 0)+1 }, timestamp: new Date().toISOString() });
  leadUpdates.push({ leadId: fu.leadId, agentFollowUpCount: (lead.agentFollowUpCount ?? 0) + 1, lastAgentFollowUpDay: day });
  statusUpdates.push({ leadId: fu.leadId, status: 'Awaiting Reply' });
}

// 4. Initial email for new leads (CloseIt's first touch)
for (const l of newLeads) {
  if (l.startType === 'cold') {
    // Will be generated in next step — for now just mark the action slot
    // (We batch this in a separate OpenAI call below; placeholder here)
    statusUpdates.push({ leadId: l.id, status: 'New' });
  }
}

// 5. Post-MoM nudges: remind user that lead replied, their turn
for (const lead of momNudgeLeads) {
  const thread = threads[lead.id] ?? [];
  const lastMsg = thread[thread.length - 1];
  notifications.push({ type: 'lead_arrived', message: `⚡ Action needed: ${lead.name} replied after your discovery call. Your response is due.` });
}

// ── Score all leads (recency + intent + frequency) ────────────────────────
const POS_KEYWORDS = ['interested', 'sounds good', 'let\'s', 'schedule', 'book', 'call', 'demo', 'yes', 'definitely', 'great', 'perfect', 'keen', 'forward', 'available', 'when can', 'happy to'];
const NEG_KEYWORDS = ['not interested', 'no thanks', 'unsubscribe', 'remove', 'stop', 'busy', 'later', 'maybe next', 'not right now'];

const allLeadsForScoring = [...leads, ...newLeads];
const scoreUpdates = allLeadsForScoring
  .filter(l => !['Closed Won','Closed Lost','Nurture'].includes(l.status))
  .map(lead => {
    const thread = threads[lead.id] ?? [];
    const leadMsgs = thread.filter(m => m.from === 'lead');
    const lastLeadMsg = leadMsgs[leadMsgs.length - 1];
    const allText = leadMsgs.map(m => m.body.toLowerCase()).join(' ');

    // Intent score (0-4)
    const posHits = POS_KEYWORDS.filter(k => allText.includes(k)).length;
    const negHits = NEG_KEYWORDS.filter(k => allText.includes(k)).length;
    const intentScore = Math.min(4, Math.max(0, posHits - negHits * 2));

    // Recency penalty (-3 to 0)
    const daysSinceReply = lastLeadMsg ? (day - lastLeadMsg.day) : day;
    const recencyPenalty = Math.max(-3, -Math.floor(daysSinceReply / lead.replyFrequencyDays));

    // Frequency bonus (0-2)
    const replyCount = leadMsgs.length;
    const expectedReplies = Math.max(1, Math.floor(day / lead.replyFrequencyDays));
    const freqBonus = replyCount >= expectedReplies ? Math.min(2, replyCount - expectedReplies + 1) : 0;

    // Discovery call bonus
    const callBonus = lead.status === 'Discovery Booked' ? 2 : 0;

    const newScore = Math.min(10, Math.max(0, 6 + intentScore + recencyPenalty + freqBonus + callBonus));
    const delta = newScore - (lead.score ?? 6);

    if (newScore < 4 && (lead.score ?? 6) >= 4) {
      notifications.push({ type: 'score_critical', message: `${lead.name}'s score dropped to ${newScore} — needs attention` });
    }

    return { leadId: lead.id, score: newScore, delta };
  });

return [{ json: { newLeads, threadMessages, scoreUpdates, statusUpdates, leadUpdates, agentActions, notifications, tasks } }];

