const assembled = $('Assemble Response').first().json;
const initialRaw = $('OpenAI: Initial Emails').first().json.choices?.[0]?.message?.content ?? '[]';
let initialEmails = [];
try { initialEmails = JSON.parse(initialRaw.replace(/```json|```/g,'').trim()); } catch {}

const day = $('Parse State').first().json.day;

// Merge initial emails into threadMessages + agentActions
const extraMessages = [];
const extraActions = [];
const extraStatusUpdates = [];

for (const ie of initialEmails) {
  const lead = assembled.newLeads.find(l => l.id === ie.leadId);
  if (!lead || !ie.emailBody) continue;
  extraMessages.push({ leadId: ie.leadId, from: 'agent', body: ie.emailBody, day });
  extraStatusUpdates.push({ leadId: ie.leadId, status: 'Contacted' });
  extraActions.push({
    id: `act_${day}_init_${ie.leadId}`,
    day,
    type: 'initial_email_sent',
    leadId: ie.leadId,
    leadName: lead.name,
    summary: `Initial ${lead.startType === 'warm' ? 'warm response' : 'cold outreach'} sent to ${lead.name} (${lead.company})`,
    actor: 'ai',
    detail: { body: ie.emailBody, startType: lead.startType },
    timestamp: new Date().toISOString()
  });
}

const finalResult = {
  newLeads: assembled.newLeads,
  threadMessages: [...assembled.threadMessages, ...extraMessages],
  scoreUpdates: assembled.scoreUpdates,
  statusUpdates: [...assembled.statusUpdates, ...extraStatusUpdates],
  leadUpdates: assembled.leadUpdates,
  agentActions: [...assembled.agentActions, ...extraActions],
  notifications: assembled.notifications,
  tasks: assembled.tasks
};

return [{ json: finalResult }];

// Prepare flat rows for Activity Log
const result = $('Merge Initial Emails').first().json;
const day = $('Parse State').first().json.day;
const rows = [];

for (const msg of result.threadMessages ?? []) {
  rows.push({ day, leadId: msg.leadId, action_type: `message_${msg.from}`, actor: msg.from, summary: msg.body.substring(0,100), detail_json: JSON.stringify(msg), timestamp: new Date().toISOString() });
}
for (const a of result.agentActions ?? []) {
  rows.push({ day, leadId: a.leadId, action_type: a.type, actor: a.actor, summary: a.summary, detail_json: JSON.stringify(a.detail), timestamp: a.timestamp });
}

return rows.length ? rows.map(r => ({ json: r })) : [{ json: { day, action_type: 'no_op', actor: 'system', summary: 'No actions this day', timestamp: new Date().toISOString() } }];
